/// Solve weighted least squares problem: (X'WX) β = X'Wz
fn solve_weighted_least_squares(
    x: &ArrayView2<f64>,
    z: &Array1<f64>,
    weights: &Array1<f64>,
) -> Result<Array1<f64>, OptimError> {
    let (n_obs, n_vars) = x.dim();

    // Convert ndarray to faer matrix
    let x_faer = Mat::from_fn(n_obs, n_vars, |i, j| x[[i, j]]);

    // Create weight matrix W^(1/2) for numerical stability
    let sqrt_weights = weights.mapv(|w| w.sqrt());

    // Create weighted design matrix and response using faer operations
    let mut x_weighted = Mat::zeros(n_obs, n_vars);
    let mut z_weighted = faer::Col::zeros(n_obs);

    for i in 0..n_obs {
        let sqrt_w = sqrt_weights[i];
        z_weighted[i] = sqrt_w * z[i];
        for j in 0..n_vars {
            x_weighted[(i, j)] = sqrt_w * x_faer[(i, j)];
        }
    }

    // Form normal equations: (X'WX) β = X'Wz using faer
    let xtw_x = x_weighted.transpose() * &x_weighted;
    let xtw_z = x_weighted.transpose() * &z_weighted;

    // Solve using faer's robust solver
    let beta_faer = xtw_x.cholesky().map_err(|_| {
        OptimError::Numerical("Failed to compute Cholesky decomposition".to_string())
    })?.solve(&xtw_z);

    // Convert back to ndarray
    let beta = Array1::from_iter((0..n_vars).map(|i| beta_faer[i]));

    Ok(beta)
}

