    LF: Fn(f64) -> f64 + Copy,
    ILF: Fn(f64) -> f64 + Copy,
    MEF: Fn(f64) -> f64 + Copy,
    VF: Fn(f64) -> f64,
    DR: Fn(f64, f64) -> f64,
